/**
 * Auto-reconnect decorator for WebSocket terminal/VNC sessions.
 *
 * Pattern: **Decorator** — wraps a {@link TerminalSession} or
 * {@link VncSession} with retry-and-reconnect behaviour. The user
 * sees the same `send` / `resize` / `close` surface; underneath, on
 * a non-user-initiated socket close (server-side termination, network
 * glitch, ticket expiry), the decorator transparently:
 *
 *   1. Re-issues the ticket via the same `connectTerminal` /
 *      `connectVnc` flow.
 *   2. Re-opens the WebSocket.
 *   3. Resumes forwarding messages to the user-supplied callbacks.
 *
 * The original session's TerminalSession / VncSession class is left
 * untouched — Open/Closed: extending behaviour without modifying the
 * decorated subject.
 */

import { Configuration } from './runtime';
import {
    connectTerminal,
    connectVnc,
    TerminalSession,
    TerminalTarget,
    TerminalCallbacks,
    VncSession,
    VncTarget,
    VncCallbacks,
} from './WebSocket';

export interface RetryOptions {
    /** Maximum number of reconnect attempts before giving up. Default: 10. */
    maxRetries?: number;
    /** Initial backoff delay in ms before the first reconnect. Default: 500. */
    initialDelayMs?: number;
    /** Maximum backoff delay (caps exponential growth). Default: 30_000. */
    maxDelayMs?: number;
    /** Multiplier applied to the delay after each failed attempt. Default: 2. */
    backoffMultiplier?: number;
    /** Called once per successful reconnect. Useful for re-syncing terminal state. */
    onReconnect?: (attempt: number) => void;
    /** Called when retries are exhausted. After this, no further reconnect happens. */
    onGiveUp?: (lastError: unknown) => void;
}

const DEFAULT_RETRY: Required<Omit<RetryOptions, 'onReconnect' | 'onGiveUp'>> = {
    maxRetries: 10,
    initialDelayMs: 500,
    maxDelayMs: 30_000,
    backoffMultiplier: 2,
};

function computeDelay(attempt: number, opts: RetryOptions): number {
    const init = opts.initialDelayMs ?? DEFAULT_RETRY.initialDelayMs;
    const max = opts.maxDelayMs ?? DEFAULT_RETRY.maxDelayMs;
    const mult = opts.backoffMultiplier ?? DEFAULT_RETRY.backoffMultiplier;
    const computed = init * Math.pow(mult, attempt);
    return Math.min(computed, max);
}

function sleep(ms: number): Promise<void> {
    return new Promise((resolve) => setTimeout(resolve, ms));
}

/**
 * Resilient terminal session — same surface as {@link TerminalSession}
 * but transparently reconnects on non-user-initiated close.
 */
export class ResilientTerminalSession {
    private session: TerminalSession;
    private closed = false;
    private attempt = 0;

    private constructor(
        session: TerminalSession,
        private readonly config: Configuration,
        private readonly target: TerminalTarget,
        private readonly userCallbacks: TerminalCallbacks,
        private readonly retry: RetryOptions,
    ) {
        this.session = session;
    }

    static async open(
        config: Configuration,
        target: TerminalTarget,
        callbacks: TerminalCallbacks = {},
        retry: RetryOptions = {},
    ): Promise<ResilientTerminalSession> {
        const wrappedCallbacks: TerminalCallbacks = {
            onMessage: callbacks.onMessage,
            onError: callbacks.onError,
            // onClose intercepted: trigger reconnect unless user-initiated.
        };
        const session = await connectTerminal(config, target, wrappedCallbacks);
        const wrapper = new ResilientTerminalSession(
            session,
            config,
            target,
            callbacks,
            retry,
        );
        wrapper.attachCloseHandler();
        return wrapper;
    }

    send(text: string): void { this.session.send(text); }
    resize(cols: number, rows: number): void { this.session.resize(cols, rows); }

    close(code = 1000, reason = 'client closed'): void {
        this.closed = true;
        this.session.close(code, reason);
    }

    private attachCloseHandler(): void {
        // The current session was opened with user callbacks attached
        // directly. To intercept its close, we re-wire onClose by
        // creating an internal listener via a setter-like proxy.
        // Simplification: we open a NEW session each retry with
        // wrapped callbacks, so the wiring is done in `reconnect()`.
        const original = (this.session as any).socket as WebSocket;
        const onCloseListener = async (event: CloseEvent) => {
            if (this.closed) {
                // User-initiated; just propagate.
                this.userCallbacks.onClose?.(event);
                return;
            }
            // Try to reconnect.
            await this.reconnect();
        };
        original.addEventListener('close', onCloseListener);
    }

    private async reconnect(): Promise<void> {
        const max = this.retry.maxRetries ?? DEFAULT_RETRY.maxRetries;
        let lastError: unknown = null;
        for (let i = 0; i < max; i++) {
            this.attempt++;
            const delay = computeDelay(i, this.retry);
            await sleep(delay);
            try {
                this.session = await connectTerminal(this.config, this.target, {
                    onMessage: this.userCallbacks.onMessage,
                    onError: this.userCallbacks.onError,
                });
                this.attachCloseHandler();
                this.retry.onReconnect?.(this.attempt);
                return;
            } catch (e) {
                lastError = e;
            }
        }
        this.retry.onGiveUp?.(lastError);
        // Fall through: notify user as if final close.
        this.userCallbacks.onClose?.({} as CloseEvent);
    }
}

/**
 * Resilient VNC session — same surface, same reconnect semantics.
 */
export class ResilientVncSession {
    private session: VncSession;
    private closed = false;
    private attempt = 0;

    private constructor(
        session: VncSession,
        private readonly config: Configuration,
        private readonly target: VncTarget,
        private readonly userCallbacks: VncCallbacks,
        private readonly retry: RetryOptions,
    ) {
        this.session = session;
    }

    static async open(
        config: Configuration,
        target: VncTarget,
        callbacks: VncCallbacks = {},
        retry: RetryOptions = {},
    ): Promise<ResilientVncSession> {
        const session = await connectVnc(config, target, {
            onFrame: callbacks.onFrame,
            onError: callbacks.onError,
        });
        const wrapper = new ResilientVncSession(session, config, target, callbacks, retry);
        wrapper.attachCloseHandler();
        return wrapper;
    }

    send(data: Uint8Array): void { this.session.send(data); }

    close(code = 1000, reason = 'client closed'): void {
        this.closed = true;
        this.session.close(code, reason);
    }

    private attachCloseHandler(): void {
        const original = (this.session as any).socket as WebSocket;
        original.addEventListener('close', async (event: CloseEvent) => {
            if (this.closed) {
                this.userCallbacks.onClose?.(event);
                return;
            }
            await this.reconnect();
        });
    }

    private async reconnect(): Promise<void> {
        const max = this.retry.maxRetries ?? DEFAULT_RETRY.maxRetries;
        let lastError: unknown = null;
        for (let i = 0; i < max; i++) {
            this.attempt++;
            await sleep(computeDelay(i, this.retry));
            try {
                this.session = await connectVnc(this.config, this.target, {
                    onFrame: this.userCallbacks.onFrame,
                    onError: this.userCallbacks.onError,
                });
                this.attachCloseHandler();
                this.retry.onReconnect?.(this.attempt);
                return;
            } catch (e) {
                lastError = e;
            }
        }
        this.retry.onGiveUp?.(lastError);
        this.userCallbacks.onClose?.({} as CloseEvent);
    }
}

